/* CompTIA AI Fundamentals :: content/quiz5.js — question bank for Domain 5 (100 items). */
window.AIFUND = window.AIFUND || {}; AIFUND.questions = AIFUND.questions || [];
AIFUND.questions.push(
{ id:"D5-001", domain:5, obj:"5.1", diff:"easy", q:"You are staring at a blank page for a newsletter and cannot think of a topic. What is the MOST effective way to use an AI chatbot to overcome this block?", options:["Ask it to brainstorm a list of possible angles so you can pick one to develop","Ask it to write the entire finished newsletter with no input from you","Ask it to guarantee the newsletter will go viral","Wait until you feel inspired and skip the AI"], answer:0, explain:"<strong>Ask it to brainstorm a list of possible angles so you can pick one to develop</strong> uses AI for its strength as an idea generator, giving you many starting points to react to and choose from.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask it to write the entire finished newsletter with no input from you</b>: skipping your own input produces generic output that does not reflect your voice or purpose, and defeats the goal of getting unstuck on your own ideas.</span><span class='qd'><b>Ask it to guarantee the newsletter will go viral</b>: no tool can guarantee an outcome, and asking for one wastes the brainstorming opportunity.</span><span class='qd'><b>Wait until you feel inspired and skip the AI</b>: waiting passively is exactly the block you are trying to break, and the AI is a fast way to generate options.</span>" },
{ id:"D5-002", domain:5, obj:"5.1", diff:"easy", q:"Which prompt is BEST for using AI to kickstart ideas for a team offsite?", options:["\"Plan my offsite.\"","\"Give me 10 varied activity ideas for a half-day team offsite focused on collaboration.\"","\"Is an offsite a good idea?\"","\"Write a 2,000-word essay about teamwork.\""], answer:1, explain:"<strong>\"Give me 10 varied activity ideas for a half-day team offsite focused on collaboration.\"</strong> is specific about quantity, format, and goal, so the AI returns a useful spread of options to choose from.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Plan my offsite.\"</b>: this is too vague to produce ideas you can react to, and gives the AI no goal, length, or constraints.</span><span class='qd'><b>\"Is an offsite a good idea?\"</b>: this asks a yes/no question rather than generating the ideas you need to get started.</span><span class='qd'><b>\"Write a 2,000-word essay about teamwork.\"</b>: an essay is not a list of actionable activity ideas and does not help you kickstart planning.</span>" },
{ id:"D5-003", domain:5, obj:"5.1", diff:"medium", q:"An AI gives you a list of 15 project ideas, but they all feel similar. What is the BEST follow-up prompt to broaden your options?", options:["\"Give me the same list again.\"","\"Just pick the best one for me.\"","\"These feel similar. Give me ideas from very different angles, including some unconventional ones.\"","\"Make the list shorter.\""], answer:2, explain:"<strong>\"These feel similar. Give me ideas from very different angles, including some unconventional ones.\"</strong> tells the AI exactly what was missing and steers it toward diversity, which is how you iterate to better brainstorming output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Give me the same list again.\"</b>: repeating the request will likely reproduce the same clustered ideas and not broaden your options.</span><span class='qd'><b>\"Just pick the best one for me.\"</b>: this narrows instead of broadens, and you have not yet seen enough variety to choose well.</span><span class='qd'><b>\"Make the list shorter.\"</b>: shortening reduces the range of ideas, which is the opposite of what you need.</span>" },
{ id:"D5-004", domain:5, obj:"5.1", diff:"easy", q:"When using AI to overcome writer's block, why is it useful to ask for MULTIPLE options rather than a single answer?", options:["Multiple options are always factually more accurate","A single answer is against the rules of every AI tool","The AI charges less for multiple options","Seeing several directions helps you react, compare, and choose a path forward"], answer:3, explain:"<strong>Seeing several directions helps you react, compare, and choose a path forward</strong>, which is the core value of AI brainstorming: it gives you material to respond to when you are stuck.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Multiple options are always factually more accurate</b>: quantity does not equal accuracy, and more ideas are not inherently more correct.</span><span class='qd'><b>The AI charges less for multiple options</b>: pricing is unrelated to whether you request one or many ideas.</span><span class='qd'><b>A single answer is against the rules of every AI tool</b>: single answers are perfectly allowed; requesting several is simply more useful for brainstorming.</span>" },
{ id:"D5-005", domain:5, obj:"5.1", diff:"medium", q:"You want an AI to help you brainstorm a name for a new coffee blend, but you keep getting bland suggestions. Which technique will MOST likely improve the ideas?", options:["Give it context and constraints, like the flavor, mood, and a few example names you like","Insist repeatedly that it try harder","Ask it to promise the name will be trademarkable","Type the request in all capital letters"], answer:0, explain:"<strong>Give it context and constraints, like the flavor, mood, and a few example names you like</strong> gives the AI something to anchor to, which produces more targeted and creative suggestions than a bare request.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Insist repeatedly that it try harder</b>: nagging does not add the information the AI needs to generate better-fitting names.</span><span class='qd'><b>Ask it to promise the name will be trademarkable</b>: an AI cannot verify trademark availability, and asking for a promise does not improve idea quality.</span><span class='qd'><b>Type the request in all capital letters</b>: capitalization does not change the substance of the output.</span>" },
{ id:"D5-006", domain:5, obj:"5.1", diff:"hard", q:"A nonprofit manager uses AI to brainstorm fundraising campaign themes. The AI's ideas are creative but assume a large budget the nonprofit does not have. What is the BEST way to fix this?", options:["Abandon AI brainstorming as unsuitable for nonprofits","Add the real budget and staffing constraints to the prompt and ask it to work within them","Use the ideas anyway and hope the budget appears","Ask the AI to raise the money itself"], answer:1, explain:"<strong>Add the real budget and staffing constraints to the prompt and ask it to work within them</strong> gives the AI the missing limits, so its next round of ideas is realistic and actionable for the nonprofit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Abandon AI brainstorming as unsuitable for nonprofits</b>: the tool works fine once you supply constraints; abandoning it discards a useful idea source.</span><span class='qd'><b>Use the ideas anyway and hope the budget appears</b>: acting on unaffordable ideas wastes effort and ignores a fixable prompting problem.</span><span class='qd'><b>Ask the AI to raise the money itself</b>: an AI cannot execute fundraising; it can only help you plan it.</span>" },
{ id:"D5-007", domain:5, obj:"5.1", diff:"medium", q:"Which of the following is the STRONGEST sign that an AI brainstorming session was productive?", options:["The AI produced exactly one idea and refused to add more","The AI used very long, technical sentences","You left with several viable directions you had not considered before","The session took as little time as possible with no reading"], answer:2, explain:"<strong>You left with several viable directions you had not considered before</strong> is the real payoff of brainstorming with AI: it expanded your thinking beyond where you started.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI produced exactly one idea and refused to add more</b>: a single idea is a weak brainstorming outcome and does not expand your options.</span><span class='qd'><b>The AI used very long, technical sentences</b>: dense wording is not a measure of idea quality or usefulness.</span><span class='qd'><b>The session took as little time as possible with no reading</b>: speed alone says nothing about whether the ideas were valuable.</span>" },
{ id:"D5-008", domain:5, obj:"5.1", diff:"easy", q:"You ask an AI, \"Help me get started on a wedding toast.\" What kind of response is MOST helpful for beating the blank-page problem?", options:["A refusal because toasts are personal","A finished toast you must read word-for-word","A single sentence with no detail","A set of prompts and structure options, like an opening line, a story, and a closing wish"], answer:3, explain:"<strong>A set of prompts and structure options, like an opening line, a story, and a closing wish</strong> gives you a scaffold to fill in with your own memories, which is exactly what breaks the blank-page block while keeping the toast personal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A refusal because toasts are personal</b>: the AI can still offer structure without writing your personal content for you.</span><span class='qd'><b>A finished toast you must read word-for-word</b>: a canned toast will feel generic and impersonal at a real wedding.</span><span class='qd'><b>A single sentence with no detail</b>: one sentence gives you almost nothing to build on.</span>" },
{ id:"D5-009", domain:5, obj:"5.1", diff:"hard", q:"A product designer wants AI help generating feature ideas but worries the AI will just repeat obvious, generic features. Which prompting strategy BEST pushes past the obvious?", options:["Ask it to list features, then ask it to critique its own list and propose bolder alternatives","Accept the first list and stop","Ask it to only give features that already exist in competitors","Tell it to avoid explaining any of its ideas"], answer:0, explain:"<strong>Ask it to list features, then ask it to critique its own list and propose bolder alternatives</strong> uses an iterate-and-challenge loop that pushes the AI beyond its first, safest suggestions toward more original ideas.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept the first list and stop</b>: the first list is usually the most generic, which is exactly what the designer wants to avoid.</span><span class='qd'><b>Ask it to only give features that already exist in competitors</b>: copying existing features guarantees unoriginal results.</span><span class='qd'><b>Tell it to avoid explaining any of its ideas</b>: removing explanations makes it harder to judge and refine the ideas, and does not improve originality.</span>" },
{ id:"D5-010", domain:5, obj:"5.1", diff:"medium", q:"An AI brainstorm gives you a promising idea, but you are not sure it fits your audience. What is the BEST next step within the same session?", options:["Post the idea publicly immediately","Describe your audience and ask the AI to pressure-test whether the idea fits them","Delete the whole conversation and start over","Ask the AI to guarantee the audience will love it"], answer:1, explain:"<strong>Describe your audience and ask the AI to pressure-test whether the idea fits them</strong> continues the session productively by adding the audience context the AI needs to give you a useful reality check.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Post the idea publicly immediately</b>: publishing before checking fit skips the judgment step and risks a poor match.</span><span class='qd'><b>Delete the whole conversation and start over</b>: discarding useful context loses your progress unnecessarily.</span><span class='qd'><b>Ask the AI to guarantee the audience will love it</b>: guarantees are impossible and do not test the idea against your specific audience.</span>" },
{ id:"D5-011", domain:5, obj:"5.1", diff:"easy", q:"Why can an AI chatbot be helpful specifically at the very START of a creative task?", options:["It removes all need for human judgment later","It always knows your personal preferences","It can quickly produce raw material and starting points to react to","It guarantees the final result will be perfect"], answer:2, explain:"<strong>It can quickly produce raw material and starting points to react to</strong> is the AI's value at the start of a task: it overcomes inertia by giving you something concrete to shape.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It removes all need for human judgment later</b>: you still must evaluate, edit, and choose; AI does not replace your judgment.</span><span class='qd'><b>It always knows your personal preferences</b>: the AI does not know your preferences unless you tell it, so it cannot always tailor to you.</span><span class='qd'><b>It guarantees the final result will be perfect</b>: no tool guarantees a perfect outcome; it only supplies a starting point.</span>" },
{ id:"D5-012", domain:5, obj:"5.1", diff:"medium", q:"You ask an AI for blog post ideas and it returns topics that are interesting but not relevant to your industry. What is the MOST likely cause?", options:["The AI is broken and should be replaced","You asked for too few ideas","AI tools cannot generate industry-specific ideas","Your prompt did not specify your industry or audience"], answer:3, explain:"<strong>Your prompt did not specify your industry or audience</strong> is the usual cause: without that context the AI defaults to broad, general topics that may miss your field.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI is broken and should be replaced</b>: off-target results from a vague prompt are a prompting issue, not a defect.</span><span class='qd'><b>AI tools cannot generate industry-specific ideas</b>: they can, and do, once you give them the relevant context.</span><span class='qd'><b>You asked for too few ideas</b>: quantity is unrelated to relevance; even one idea can be on-target with the right context.</span>" },
{ id:"D5-013", domain:5, obj:"5.1", diff:"hard", q:"A manager wants to use AI to generate meeting agenda ideas but is concerned the team will feel the agenda is impersonal or robotic. What is the BEST balanced approach?", options:["Use the AI to draft options, then select and adapt them with the team's real priorities in mind","Refuse to use AI for anything team-facing","Use the AI's agenda verbatim and say nothing","Ask the AI to imitate a specific team member's personality"], answer:0, explain:"<strong>Use the AI to draft options, then select and adapt them with the team's real priorities in mind</strong> keeps the speed of AI while ensuring the final agenda reflects genuine team needs, avoiding a robotic feel.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use the AI's agenda verbatim and say nothing</b>: unedited output is exactly what feels impersonal and may miss real priorities.</span><span class='qd'><b>Refuse to use AI for anything team-facing</b>: this discards a useful drafting aid; the fix is human curation, not avoidance.</span><span class='qd'><b>Ask the AI to imitate a specific team member's personality</b>: mimicking a real person can feel deceptive and does not make the agenda more relevant.</span>" },
{ id:"D5-014", domain:5, obj:"5.1", diff:"medium", q:"Which request would MOST effectively use an AI to help you escape a creative rut on a marketing slogan?", options:["\"Give me one slogan and don't explain it.\"","\"Generate 20 slogans across playful, bold, and minimalist tones so I can compare styles.\"","\"Tell me if slogans matter.\"","\"Summarize the history of advertising.\""], answer:1, explain:"<strong>\"Generate 20 slogans across playful, bold, and minimalist tones so I can compare styles.\"</strong> asks for variety across defined styles, giving you a rich set to react to and breaking the rut.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Give me one slogan and don't explain it.\"</b>: one option provides little to compare and is unlikely to spark new direction.</span><span class='qd'><b>\"Tell me if slogans matter.\"</b>: this is a discussion question, not a request that generates usable slogans.</span><span class='qd'><b>\"Summarize the history of advertising.\"</b>: a history lesson does not produce slogan options for your task.</span>" },
{ id:"D5-015", domain:5, obj:"5.1", diff:"easy", q:"After AI brainstorming, what should you always do before treating an idea as final?", options:["Publish it without review","Assume the AI checked it for accuracy","Apply your own judgment to evaluate and refine it","Discard your own opinions in favor of the AI's"], answer:2, explain:"<strong>Apply your own judgment to evaluate and refine it</strong> is essential because AI ideas are starting points that you, the human, must vet for fit, accuracy, and quality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it without review</b>: skipping review risks errors and poor fit that only human judgment can catch.</span><span class='qd'><b>Assume the AI checked it for accuracy</b>: AI does not reliably verify its own output, so you cannot assume it is accurate.</span><span class='qd'><b>Discard your own opinions in favor of the AI's</b>: your expertise and context are exactly what make an idea good; you should not defer entirely to the AI.</span>" },
{ id:"D5-016", domain:5, obj:"5.1", diff:"medium", q:"A teacher wants AI to help brainstorm engaging ways to teach fractions to 4th graders. What context in the prompt would MOST improve the results?", options:["The teacher's favorite color","The teacher's years of experience only","The price of the AI subscription","The students' age, class size, and available materials"], answer:3, explain:"<strong>The students' age, class size, and available materials</strong> gives the AI the practical constraints it needs to suggest activities that will actually work in that classroom.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The teacher's favorite color</b>: this is irrelevant to how to teach fractions.</span><span class='qd'><b>The price of the AI subscription</b>: cost has no bearing on the teaching ideas generated.</span><span class='qd'><b>The teacher's years of experience only</b>: experience alone does not tell the AI about the students or resources, which are what shape the activities.</span>" },
{ id:"D5-017", domain:5, obj:"5.2", diff:"easy", q:"You have a rough first draft and want AI to improve it. What is the BEST way to start?", options:["Paste the draft and ask the AI to revise it for clarity while keeping your meaning","Ask the AI to write a brand-new document ignoring your draft","Ask the AI whether writing is hard","Delete your draft and describe it from memory"], answer:0, explain:"<strong>Paste the draft and ask the AI to revise it for clarity while keeping your meaning</strong> lets the AI work on your actual content and preserve your intent, which is the point of a revision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the AI to write a brand-new document ignoring your draft</b>: ignoring your draft discards your work and produces something that may not match your intent.</span><span class='qd'><b>Ask the AI whether writing is hard</b>: this is a chat question that does not revise your draft.</span><span class='qd'><b>Delete your draft and describe it from memory</b>: recreating it from memory loses detail and wastes the draft you already have.</span>" },
{ id:"D5-018", domain:5, obj:"5.2", diff:"easy", q:"You need the same message written for two audiences: executives and new interns. What should you tell the AI?", options:["Nothing; one version works for everyone","The specific audience for each version, so it can adjust tone and detail","To make both versions as long as possible","To use the most advanced vocabulary for both"], answer:1, explain:"<strong>The specific audience for each version, so it can adjust tone and detail</strong> lets the AI tailor language and depth appropriately, since executives and interns need different framing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Nothing; one version works for everyone</b>: a single version rarely fits both a busy executive and a brand-new intern equally well.</span><span class='qd'><b>To make both versions as long as possible</b>: length is not the goal; appropriate tone and detail for each audience is.</span><span class='qd'><b>To use the most advanced vocabulary for both</b>: complex vocabulary may confuse interns and is not automatically better for executives.</span>" },
{ id:"D5-019", domain:5, obj:"5.2", diff:"medium", q:"An AI rewrites your email but changes a key fact you stated. What is the correct response?", options:["Trust the AI since it is more advanced than you","Assume the new fact must be right","Correct the fact yourself, since you are responsible for accuracy","Publish it and fix errors only if someone complains"], answer:2, explain:"<strong>Correct the fact yourself, since you are responsible for accuracy</strong> reflects that AI can introduce errors and the human sender owns the final content's correctness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the AI since it is more advanced than you</b>: sophistication does not make an AI factually reliable, and it may have altered your fact incorrectly.</span><span class='qd'><b>Assume the new fact must be right</b>: assuming correctness without checking is how errors get published.</span><span class='qd'><b>Publish it and fix errors only if someone complains</b>: publishing known-risky content and waiting for complaints is careless and can cause harm.</span>" },
{ id:"D5-020", domain:5, obj:"5.2", diff:"medium", q:"You ask AI to make a paragraph \"more professional.\" The result is stiff and hard to read. What is the BEST follow-up?", options:["\"Never mind, I'll keep the original.\"","\"Make it longer.\"","\"Add more jargon.\"","\"Make it professional but still warm and easy to read, like a friendly colleague.\""], answer:3, explain:"<strong>\"Make it professional but still warm and easy to read, like a friendly colleague.\"</strong> gives the AI a clearer, more nuanced target for tone, correcting the overly stiff result.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Never mind, I'll keep the original.\"</b>: giving up forgoes an easy fix that a better tone instruction would achieve.</span><span class='qd'><b>\"Add more jargon.\"</b>: jargon usually makes writing harder to read, worsening the problem.</span><span class='qd'><b>\"Make it longer.\"</b>: length does not address the stiffness and may make it worse.</span>" },
{ id:"D5-021", domain:5, obj:"5.2", diff:"hard", q:"You must adapt a detailed technical report into a one-page summary for a busy board. Which instruction to the AI will produce the BEST result?", options:["\"Summarize this, focusing on decisions and impacts the board cares about, in plain language, under one page.\"","\"Shorten this a little.\"","\"Keep every technical detail but make it fit one page.\"","\"Rewrite it using more acronyms.\""], answer:0, explain:"<strong>\"Summarize this, focusing on decisions and impacts the board cares about, in plain language, under one page.\"</strong> specifies audience needs, tone, focus, and length, which are exactly the constraints needed for an effective board summary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Shorten this a little.\"</b>: vague shortening will not reliably reach one page or refocus on what the board needs.</span><span class='qd'><b>\"Keep every technical detail but make it fit one page.\"</b>: forcing all detail onto one page defeats the purpose of a board-level summary.</span><span class='qd'><b>\"Rewrite it using more acronyms.\"</b>: acronyms tend to confuse a non-technical board rather than clarify.</span>" },
{ id:"D5-022", domain:5, obj:"5.2", diff:"medium", q:"Which of the following is the BEST reason to specify a desired FORMAT (such as bullet points or a table) when asking AI to draft content?", options:["Formats make the AI run faster","A clear format makes the output easier for your reader to use and scan","Formatting is required by law for all documents","Bullet points are always better than paragraphs"], answer:1, explain:"<strong>A clear format makes the output easier for your reader to use and scan</strong> is the practical reason to specify format: it aligns the output with how your audience will consume it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Formats make the AI run faster</b>: formatting does not meaningfully affect speed.</span><span class='qd'><b>Formatting is required by law for all documents</b>: there is no such universal legal requirement.</span><span class='qd'><b>Bullet points are always better than paragraphs</b>: the best format depends on the content and reader, not a blanket rule.</span>" },
{ id:"D5-023", domain:5, obj:"5.2", diff:"easy", q:"You want AI to shorten a wordy message without losing the main point. What should you ask?", options:["\"Make it twice as long.\"","\"Add three new paragraphs.\"","\"Tighten this to about half the length while keeping the main point.\"","\"Translate it into legal language.\""], answer:2, explain:"<strong>\"Tighten this to about half the length while keeping the main point.\"</strong> gives a clear length target and a constraint to preserve meaning, which is exactly how to get a concise revision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Make it twice as long.\"</b>: lengthening is the opposite of shortening.</span><span class='qd'><b>\"Add three new paragraphs.\"</b>: adding content works against the goal of a shorter message.</span><span class='qd'><b>\"Translate it into legal language.\"</b>: legalese usually adds length and complexity, not brevity.</span>" },
{ id:"D5-024", domain:5, obj:"5.2", diff:"medium", q:"You ask an AI to rewrite a customer apology to sound sincere. Before sending it, what is the MOST important check?", options:["That it uses long words","That it includes at least one emoji","That it is exactly 100 words","That it accurately reflects what actually happened and what you will do about it"], answer:3, explain:"<strong>That it accurately reflects what actually happened and what you will do about it</strong> matters most because an apology that misstates facts or promises damages trust more than it repairs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>That it uses long words</b>: vocabulary complexity does not make an apology sincere or accurate.</span><span class='qd'><b>That it is exactly 100 words</b>: an arbitrary length has nothing to do with the apology being truthful and appropriate.</span><span class='qd'><b>That it includes at least one emoji</b>: an emoji is a stylistic choice, not a substitute for accuracy in a sensitive message.</span>" },
{ id:"D5-025", domain:5, obj:"5.2", diff:"hard", q:"A grant writer uses AI to revise a proposal. The AI's version reads well but adds a statistic that was not in the source and that the writer cannot verify. What should the writer do?", options:["Remove or verify the statistic before submitting, since unverifiable claims are a risk","Keep the statistic because it strengthens the proposal","Ask the AI to add more statistics for balance","Submit it and cite the AI as the source"], answer:0, explain:"<strong>Remove or verify the statistic before submitting, since unverifiable claims are a risk</strong> is correct: AI can fabricate plausible-sounding numbers, and submitting an unverifiable stat can undermine credibility or cause harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep the statistic because it strengthens the proposal</b>: a fabricated or unverifiable figure is a liability, not a strength.</span><span class='qd'><b>Ask the AI to add more statistics for balance</b>: adding more unverifiable numbers compounds the problem.</span><span class='qd'><b>Submit it and cite the AI as the source</b>: citing the AI does not make an invented statistic true or acceptable in a grant proposal.</span>" },
{ id:"D5-026", domain:5, obj:"5.2", diff:"medium", q:"Which prompt BEST directs an AI to match a specific brand tone?", options:["\"Write it however you want.\"","\"Write in our brand voice: friendly, concise, and encouraging. Here are two examples of our past posts.\"","\"Use as many adjectives as possible.\"","\"Write it in a random tone.\""], answer:1, explain:"<strong>\"Write in our brand voice: friendly, concise, and encouraging. Here are two examples of our past posts.\"</strong> defines the tone in words and provides examples, giving the AI a concrete target to match.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Write it however you want.\"</b>: leaving tone open guarantees it may not match your brand.</span><span class='qd'><b>\"Use as many adjectives as possible.\"</b>: piling on adjectives is a stylistic gimmick, not a brand-voice match.</span><span class='qd'><b>\"Write it in a random tone.\"</b>: a random tone is the opposite of a consistent brand voice.</span>" },
{ id:"D5-027", domain:5, obj:"5.2", diff:"easy", q:"When AI drafts something for you, who is ultimately responsible for the accuracy and appropriateness of the final version you send?", options:["The AI company","No one, since AI wrote it","You, the person who sends it","The reader who receives it"], answer:2, explain:"<strong>You, the person who sends it</strong> are responsible, because AI is a drafting aid and the human who publishes or sends the content owns its accuracy and tone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI company</b>: the vendor provides a tool but does not take responsibility for how you use its output.</span><span class='qd'><b>No one, since AI wrote it</b>: content you send always has an accountable human behind it.</span><span class='qd'><b>The reader who receives it</b>: the recipient has no control over what you chose to send.</span>" },
{ id:"D5-028", domain:5, obj:"5.2", diff:"medium", q:"You ask AI to reformat a long paragraph into a table, but some information does not fit neatly into columns. What is the BEST response?", options:["Force everything into the table even if it distorts the meaning","Delete the information that does not fit","Give up on formatting entirely","Ask the AI to use a table for the structured parts and keep the rest as short notes"], answer:3, explain:"<strong>Ask the AI to use a table for the structured parts and keep the rest as short notes</strong> matches the format to the content, using a table where it helps and prose where it does not.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Force everything into the table even if it distorts the meaning</b>: distorting meaning to fit a format harms clarity.</span><span class='qd'><b>Give up on formatting entirely</b>: abandoning formatting throws away the readability gains a table offers for the structured parts.</span><span class='qd'><b>Delete the information that does not fit</b>: removing valid information to suit a layout loses content the reader may need.</span>" },
{ id:"D5-029", domain:5, obj:"5.2", diff:"hard", q:"You are revising a policy document with AI and want to preserve exact legal wording in certain clauses while improving readability elsewhere. What is the BEST instruction?", options:["\"Improve readability throughout, but do not change the wording inside the clauses I marked as legal.\"","\"Rewrite the whole thing freely.\"","\"Change every sentence, including the legal clauses.\"","\"Only fix spelling and nothing else.\""], answer:0, explain:"<strong>\"Improve readability throughout, but do not change the wording inside the clauses I marked as legal.\"</strong> protects the parts that must stay exact while still improving the rest, which is the precise control this task needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Rewrite the whole thing freely.\"</b>: free rewriting risks altering legally binding language that must remain intact.</span><span class='qd'><b>\"Change every sentence, including the legal clauses.\"</b>: changing legal clauses can create legal problems and is exactly what you want to prevent.</span><span class='qd'><b>\"Only fix spelling and nothing else.\"</b>: this is too narrow and would not improve readability where you actually want it improved.</span>" },
{ id:"D5-030", domain:5, obj:"5.2", diff:"medium", q:"An AI produces a draft that is well written but drifts off your intended topic. What does this MOST likely indicate about your prompt?", options:["The AI dislikes your topic","Your prompt did not clearly state the focus or scope","AI cannot stay on topic ever","You should switch to a different device"], answer:1, explain:"<strong>Your prompt did not clearly state the focus or scope</strong> is the usual reason for topic drift: a vague or broad prompt lets the AI wander.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI dislikes your topic</b>: AI has no preferences and does not avoid topics out of dislike.</span><span class='qd'><b>AI cannot stay on topic ever</b>: AI stays on topic well when the prompt is specific.</span><span class='qd'><b>You should switch to a different device</b>: the device is irrelevant to topic focus, which is set by the prompt.</span>" },
{ id:"D5-031", domain:5, obj:"5.2", diff:"easy", q:"You want AI to change a message from casual to formal. Which single word BEST tells it what you want to adjust?", options:["Length","Font","Tone","Color"], answer:2, explain:"<strong>Tone</strong> is the dimension that captures the shift from casual to formal, which is what you are asking the AI to change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Length</b>: length is about how long the message is, not how casual or formal it sounds.</span><span class='qd'><b>Font</b>: font is a visual typeface choice, not the formality of the writing.</span><span class='qd'><b>Color</b>: color is purely visual and unrelated to casual-versus-formal wording.</span>" },
{ id:"D5-032", domain:5, obj:"5.2", diff:"hard", q:"A communications lead asks AI to draft an announcement, then notices the AI adopted a confident tone about a launch date that is still tentative. What is the BEST fix?", options:["Leave it; confidence is good in announcements","Publish immediately before the date changes","Remove the date entirely and hope no one asks","Tell the AI the date is tentative and ask it to use appropriately cautious wording"], answer:3, explain:"<strong>Tell the AI the date is tentative and ask it to use appropriately cautious wording</strong> aligns the tone with reality, since overstating certainty about a tentative date can mislead the audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Leave it; confidence is good in announcements</b>: false confidence about an uncertain date can create expectations you cannot meet.</span><span class='qd'><b>Remove the date entirely and hope no one asks</b>: hiding the date avoids the wording problem but may leave readers less informed than intended; adjusting the tone is more honest and useful.</span><span class='qd'><b>Publish immediately before the date changes</b>: rushing to publish inaccurate certainty is careless and can damage credibility.</span>" },
{ id:"D5-033", domain:5, obj:"5.3", diff:"easy", q:"You want an AI image tool to create art for a blog. Which practice is MOST important for using it safely and responsibly?", options:["Avoiding prompts that impersonate real people or copy a living artist's identity","Requesting images of real named individuals without their consent","Removing all captions so no one knows it is AI","Claiming the image is a real photograph"], answer:0, explain:"<strong>Avoiding prompts that impersonate real people or copy a living artist's identity</strong> respects consent and rights, which is central to generating media responsibly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Requesting images of real named individuals without their consent</b>: generating identifiable real people without consent raises serious ethical and legal issues.</span><span class='qd'><b>Removing all captions so no one knows it is AI</b>: hiding that an image is AI-generated is deceptive when disclosure is expected.</span><span class='qd'><b>Claiming the image is a real photograph</b>: misrepresenting AI art as a real photo is dishonest and can mislead viewers.</span>" },
{ id:"D5-034", domain:5, obj:"5.3", diff:"easy", q:"You ask an AI to critique your essay draft. What is the BEST way to get useful feedback?", options:["Ask, \"Is this good?\"","Ask it to identify unclear points, weak arguments, and specific suggestions to improve","Ask it to rewrite the whole essay silently","Ask it to only say positive things"], answer:1, explain:"<strong>Ask it to identify unclear points, weak arguments, and specific suggestions to improve</strong> directs the AI toward actionable, specific critique rather than a vague verdict.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask, \"Is this good?\"</b>: a yes/no question yields shallow feedback you cannot act on.</span><span class='qd'><b>Ask it to rewrite the whole essay silently</b>: a silent rewrite gives you a new draft but no understanding of what to improve.</span><span class='qd'><b>Ask it to only say positive things</b>: praise-only feedback hides the problems you need to fix.</span>" },
{ id:"D5-035", domain:5, obj:"5.3", diff:"medium", q:"An AI critiques your presentation and says every slide is \"perfect.\" Why should you be cautious about this feedback?", options:["AI is legally required to praise your work","Perfect feedback proves the slides need no human review","Uniform praise may mean the critique was shallow; ask for specific weaknesses","AI never makes mistakes in critique"], answer:2, explain:"<strong>Uniform praise may mean the critique was shallow; ask for specific weaknesses</strong> is the right instinct, because a genuinely useful critique usually surfaces at least some areas to improve.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI is legally required to praise your work</b>: there is no such requirement, and praise is not a sign of quality.</span><span class='qd'><b>Perfect feedback proves the slides need no human review</b>: AI feedback does not replace your own review and may simply be uncritical.</span><span class='qd'><b>AI never makes mistakes in critique</b>: AI can and does give flawed or generic critiques.</span>" },
{ id:"D5-036", domain:5, obj:"5.3", diff:"medium", q:"You generate an AI image for a client project. What is the BEST step to check before using it commercially?", options:["Assume all AI images are free to use anywhere","Use it and address any issues only if sued","Ask the AI to promise it is copyright-free","Review the tool's usage terms and any content or licensing restrictions"], answer:3, explain:"<strong>Review the tool's usage terms and any content or licensing restrictions</strong> is essential because commercial rights and restrictions vary by tool, and you must know them before using the image.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume all AI images are free to use anywhere</b>: usage rights differ by platform and cannot be assumed.</span><span class='qd'><b>Ask the AI to promise it is copyright-free</b>: a chatbot's promise is not a reliable legal clearance.</span><span class='qd'><b>Use it and address any issues only if sued</b>: waiting for a lawsuit is reckless when the terms are available to check upfront.</span>" },
{ id:"D5-037", domain:5, obj:"5.3", diff:"hard", q:"A marketer asks AI to generate a product photo, and the result closely mimics a well-known photographer's signature style, which the marketer named in the prompt. What is the MOST responsible action?", options:["Reconsider and regenerate without imitating a specific living artist's identifiable style","Publish it because AI made it, so no one owns the style","Add a watermark and publish anyway","Sell prints of the image"], answer:0, explain:"<strong>Reconsider and regenerate without imitating a specific living artist's identifiable style</strong> avoids appropriating a named creator's distinctive identity, which is an ethical and potential legal concern.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it because AI made it, so no one owns the style</b>: deliberately copying a named living artist's identity raises real ethical and reputational risks regardless of the tool.</span><span class='qd'><b>Add a watermark and publish anyway</b>: a watermark does not resolve the concern of imitating a specific artist's identity.</span><span class='qd'><b>Sell prints of the image</b>: commercializing an image that mimics a named artist compounds the problem.</span>" },
{ id:"D5-038", domain:5, obj:"5.3", diff:"medium", q:"When you ask AI to critique your work, why is it valuable to ask it to explain the REASONING behind each suggestion?", options:["Reasoning makes the response longer to justify the cost","Understanding the why helps you learn and decide which suggestions to accept","AI cannot give suggestions without reasoning","Reasoning guarantees the critique is correct"], answer:1, explain:"<strong>Understanding the why helps you learn and decide which suggestions to accept</strong> is the benefit: the reasoning lets you judge each suggestion rather than blindly applying it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reasoning makes the response longer to justify the cost</b>: length is not the point, and reasoning is about understanding, not cost.</span><span class='qd'><b>AI cannot give suggestions without reasoning</b>: AI can give bare suggestions; you are choosing to ask for reasoning.</span><span class='qd'><b>Reasoning guarantees the critique is correct</b>: an explanation can still be wrong; it aids judgment but does not guarantee accuracy.</span>" },
{ id:"D5-039", domain:5, obj:"5.3", diff:"easy", q:"You want to disclose that a blog's header image was AI-generated. Which caption is MOST transparent?", options:["\"Photo by our staff.\"","No caption at all","\"Image generated with an AI tool.\"","\"Real, untouched photograph.\""], answer:2, explain:"<strong>\"Image generated with an AI tool.\"</strong> honestly states the image's origin, which is the transparent choice when disclosure is appropriate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Photo by our staff.\"</b>: crediting staff for an AI image is inaccurate and misleading.</span><span class='qd'><b>No caption at all</b>: omitting a caption hides the AI origin, which is not transparent.</span><span class='qd'><b>\"Real, untouched photograph.\"</b>: calling an AI image a real photograph is a false statement.</span>" },
{ id:"D5-040", domain:5, obj:"5.3", diff:"hard", q:"You ask AI to critique your business plan, and it identifies a flaw in your financial assumptions that you believe is actually correct. What is the BEST response?", options:["Immediately change your plan to match the AI","Ignore all AI critique from now on","Ask the AI to apologize","Investigate the flagged point yourself to confirm who is right, since AI can be wrong"], answer:3, explain:"<strong>Investigate the flagged point yourself to confirm who is right, since AI can be wrong</strong> treats the critique as a prompt to verify, respecting that both you and the AI could be mistaken.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately change your plan to match the AI</b>: changing without checking risks acting on a mistaken critique.</span><span class='qd'><b>Ignore all AI critique from now on</b>: dismissing all future critique overreacts to one disputable point and loses a useful tool.</span><span class='qd'><b>Ask the AI to apologize</b>: an apology does nothing to resolve which assumption is actually correct.</span>" },
{ id:"D5-041", domain:5, obj:"5.3", diff:"medium", q:"You use AI to generate background music for a video. What responsible step should you take regarding rights?", options:["Check the tool's licensing terms to confirm you may use the audio in your video","Assume it is fine because AI made it","Credit a random human composer","Only use it if it sounds like a famous song"], answer:0, explain:"<strong>Check the tool's licensing terms to confirm you may use the audio in your video</strong> is the responsible move, since AI-generated audio still comes with usage terms you must respect.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is fine because AI made it</b>: AI origin does not automatically grant unrestricted usage rights.</span><span class='qd'><b>Credit a random human composer</b>: crediting someone who did not create it is false attribution.</span><span class='qd'><b>Only use it if it sounds like a famous song</b>: sounding like a famous song is actually a red flag for potential rights issues, not a green light.</span>" },
{ id:"D5-042", domain:5, obj:"5.3", diff:"medium", q:"An AI's critique of your report is generic (\"add more detail,\" \"be clearer\"). What follow-up will make the feedback MORE useful?", options:["\"Give me the same feedback again.\"","\"Point to the exact sentences that are unclear and suggest concrete rewrites.\"","\"Just tell me it's fine.\"","\"Make the report shorter.\""], answer:1, explain:"<strong>\"Point to the exact sentences that are unclear and suggest concrete rewrites.\"</strong> forces the AI from vague advice into specific, actionable feedback tied to your actual text.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Give me the same feedback again.\"</b>: repeating the request reproduces the same generic advice.</span><span class='qd'><b>\"Just tell me it's fine.\"</b>: seeking reassurance abandons the goal of improving the report.</span><span class='qd'><b>\"Make the report shorter.\"</b>: shortening does not address the vagueness of the feedback or clarify the unclear parts.</span>" },
{ id:"D5-043", domain:5, obj:"5.3", diff:"easy", q:"Why is it good practice to disclose when content is AI-generated in contexts where the audience expects human authorship?", options:["Disclosure makes the content rank higher automatically","It is required for every message ever written","It maintains honesty and trust with your audience","Disclosure improves the writing quality"], answer:2, explain:"<strong>It maintains honesty and trust with your audience</strong> is the reason to disclose: transparency preserves credibility when readers would otherwise assume human authorship.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disclosure makes the content rank higher automatically</b>: disclosure is about honesty, not search ranking.</span><span class='qd'><b>It is required for every message ever written</b>: disclosure norms depend on context and expectations, not a universal mandate.</span><span class='qd'><b>Disclosure improves the writing quality</b>: labeling content as AI-made does not change how well it is written.</span>" },
{ id:"D5-044", domain:5, obj:"5.3", diff:"hard", q:"A designer uses AI to critique a logo. The AI suggests changes that would make it resemble a competitor's well-known logo. What should the designer do?", options:["Apply the changes since the AI recommended them","Ask the AI to make it even more similar","Copy the competitor's logo exactly to be safe","Recognize the risk of confusion or infringement and reject those specific suggestions"], answer:3, explain:"<strong>Recognize the risk of confusion or infringement and reject those specific suggestions</strong> applies human judgment where AI advice would lead toward imitating a competitor's protected mark.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Apply the changes since the AI recommended them</b>: following advice that creates infringement risk is unwise; you must vet AI suggestions.</span><span class='qd'><b>Copy the competitor's logo exactly to be safe</b>: exact copying is clearly infringing and worse, not safer.</span><span class='qd'><b>Ask the AI to make it even more similar</b>: increasing similarity deepens the legal and brand-confusion risk.</span>" },
{ id:"D5-045", domain:5, obj:"5.3", diff:"medium", q:"You want AI to critique your resume. Which piece of context will MOST improve the critique?", options:["The specific job or role you are applying for","Your favorite hobby","The color of the paper","The AI's own resume"], answer:0, explain:"<strong>The specific job or role you are applying for</strong> lets the AI tailor its critique to what that role values, making the feedback far more relevant.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Your favorite hobby</b>: a hobby rarely shapes how a resume should be critiqued for a role.</span><span class='qd'><b>The color of the paper</b>: paper color is irrelevant to the substance of a resume critique.</span><span class='qd'><b>The AI's own resume</b>: an AI has no resume, and this provides no useful context.</span>" },
{ id:"D5-046", domain:5, obj:"5.3", diff:"medium", q:"An AI generates an infographic that includes a statistic you did not provide and cannot source. Before publishing, what should you do?", options:["Publish it; infographics look authoritative anyway","Verify or remove the statistic, since unsourced numbers can mislead readers","Add more unsourced statistics to look thorough","Assume the AI pulled it from a reliable source"], answer:1, explain:"<strong>Verify or remove the statistic, since unsourced numbers can mislead readers</strong> is the safe practice, because AI may invent figures and publishing them can spread misinformation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it; infographics look authoritative anyway</b>: looking authoritative while being unverified is exactly how misinformation spreads.</span><span class='qd'><b>Add more unsourced statistics to look thorough</b>: more unsourced numbers multiply the risk of misleading readers.</span><span class='qd'><b>Assume the AI pulled it from a reliable source</b>: AI does not reliably cite real sources, so you cannot assume the figure is sound.</span>" },
{ id:"D5-047", domain:5, obj:"5.3", diff:"easy", q:"What is a realistic and appropriate use of AI image generation for a small business?", options:["Creating fake photos of the CEO doing things they never did","Generating images of celebrities endorsing the product without permission","Producing original illustrations for a blog while disclosing they are AI-generated","Passing AI art off as award-winning photography"], answer:2, explain:"<strong>Producing original illustrations for a blog while disclosing they are AI-generated</strong> is a legitimate, transparent use that adds value without deceiving anyone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Creating fake photos of the CEO doing things they never did</b>: fabricating events is deceptive and can be defamatory.</span><span class='qd'><b>Generating images of celebrities endorsing the product without permission</b>: unauthorized endorsements misuse a person's likeness and are legally risky.</span><span class='qd'><b>Passing AI art off as award-winning photography</b>: misrepresenting AI art as photography is dishonest.</span>" },
{ id:"D5-048", domain:5, obj:"5.3", diff:"hard", q:"You ask AI to critique a sensitive internal memo about layoffs. The AI's tone suggestions make it sound cheerful. What is the BEST judgment call?", options:["Use the cheerful tone to keep morale up","Delete the memo and send nothing","Add jokes to lighten it further","Override the suggestion; the tone should be respectful and serious for the situation"], answer:3, explain:"<strong>Override the suggestion; the tone should be respectful and serious for the situation</strong> reflects that human judgment about context must guide tone, especially for sensitive topics where AI may misjudge.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use the cheerful tone to keep morale up</b>: a cheerful tone about layoffs reads as tone-deaf and disrespectful.</span><span class='qd'><b>Add jokes to lighten it further</b>: humor about layoffs is inappropriate and harmful.</span><span class='qd'><b>Delete the memo and send nothing</b>: withholding necessary communication is not the fix; adjusting the tone is.</span>" },
{ id:"D5-049", domain:5, obj:"5.4", diff:"easy", q:"You want to use AI as a study partner to learn a new topic. Which approach helps you actually LEARN rather than just get answers?", options:["Ask it to explain concepts, quiz you, and check your understanding","Ask it to give you the final answers to copy without explanation","Ask it to take the test for you","Ask it to summarize so you never read the material"], answer:0, explain:"<strong>Ask it to explain concepts, quiz you, and check your understanding</strong> engages you in active learning, which builds real understanding rather than just handing over answers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask it to give you the final answers to copy without explanation</b>: copying answers skips the learning and leaves you unable to reason on your own.</span><span class='qd'><b>Ask it to take the test for you</b>: having the AI take a test is dishonest and teaches you nothing.</span><span class='qd'><b>Ask it to summarize so you never read the material</b>: relying only on summaries to avoid learning undermines genuine understanding.</span>" },
{ id:"D5-050", domain:5, obj:"5.4", diff:"easy", q:"A student uses AI to write their entire graded essay and submits it as their own work. This is BEST described as:", options:["Effective studying","An academic integrity violation","A recommended use of AI","A form of citation"], answer:1, explain:"<strong>An academic integrity violation</strong> is correct, because submitting AI-written work as your own misrepresents authorship and typically breaks academic honesty rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Effective studying</b>: outsourcing the whole essay is the opposite of studying, since no learning occurs.</span><span class='qd'><b>A recommended use of AI</b>: passing off AI work as your own is not recommended and is usually prohibited.</span><span class='qd'><b>A form of citation</b>: citation credits sources; submitting unattributed AI work as original is not citing anything.</span>" },
{ id:"D5-051", domain:5, obj:"5.4", diff:"medium", q:"Which prompt turns AI into an effective quiz partner for exam prep?", options:["\"Give me the answer key.\"","\"Write my exam for me.\"","\"Ask me 10 practice questions one at a time, wait for my answer, then explain if I'm wrong.\"","\"Tell me I'll pass.\""], answer:2, explain:"<strong>\"Ask me 10 practice questions one at a time, wait for my answer, then explain if I'm wrong.\"</strong> creates an interactive quizzing loop that tests recall and corrects misunderstandings, which is how AI supports real study.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Give me the answer key.\"</b>: an answer key skips the practice that builds retention.</span><span class='qd'><b>\"Write my exam for me.\"</b>: this is dishonest and teaches nothing.</span><span class='qd'><b>\"Tell me I'll pass.\"</b>: reassurance does not prepare you for the material.</span>" },
{ id:"D5-052", domain:5, obj:"5.4", diff:"medium", q:"When using AI as a tutor, why should you verify important facts it teaches you against a trusted source?", options:["AI is always wrong","Verification is only needed for math","Trusted sources are always AI-generated","AI can state incorrect information confidently, so verification protects your learning"], answer:3, explain:"<strong>AI can state incorrect information confidently, so verification protects your learning</strong> is the key reason: an AI tutor may present errors as fact, and checking guards against learning something wrong.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI is always wrong</b>: AI is often right, so \"always wrong\" is inaccurate; the point is that it is not always reliable.</span><span class='qd'><b>Trusted sources are always AI-generated</b>: trusted sources are typically vetted human or institutional references, not necessarily AI output.</span><span class='qd'><b>Verification is only needed for math</b>: verification matters across all subjects, not just math.</span>" },
{ id:"D5-053", domain:5, obj:"5.4", diff:"hard", q:"A university allows AI for brainstorming and outlining but requires that final writing be the student's own. A student uses AI to outline an essay, then writes the essay themselves. Is this acceptable?", options:["Yes, because it follows the stated policy allowing AI for outlining","No, any AI use is cheating","No, outlines must be handwritten","Yes, but only if the student hides the AI use"], answer:0, explain:"<strong>Yes, because it follows the stated policy allowing AI for outlining</strong> is correct: the student used AI within the permitted scope and did the graded writing themselves.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>No, any AI use is cheating</b>: the policy explicitly permits AI for brainstorming and outlining, so it is not cheating here.</span><span class='qd'><b>No, outlines must be handwritten</b>: the policy sets no such handwriting requirement.</span><span class='qd'><b>Yes, but only if the student hides the AI use</b>: hiding permitted use is unnecessary and dishonest; following the policy openly is the right approach.</span>" },
{ id:"D5-054", domain:5, obj:"5.4", diff:"medium", q:"You want AI to help you understand a difficult concept you keep misunderstanding. Which request is MOST effective?", options:["\"Just give me the definition.\"","\"Explain it in simple terms, give an everyday analogy, then ask me a question to check I understood.\"","\"Make it as technical as possible.\"","\"Skip the explanation and give me a quiz score.\""], answer:1, explain:"<strong>\"Explain it in simple terms, give an everyday analogy, then ask me a question to check I understood.\"</strong> combines simplification, analogy, and a comprehension check, which is a strong recipe for grasping a tricky concept.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Just give me the definition.\"</b>: a bare definition often does not resolve a persistent misunderstanding.</span><span class='qd'><b>\"Make it as technical as possible.\"</b>: added technicality usually deepens confusion for something you already find difficult.</span><span class='qd'><b>\"Skip the explanation and give me a quiz score.\"</b>: a score without explanation does not help you understand the concept.</span>" },
{ id:"D5-055", domain:5, obj:"5.4", diff:"easy", q:"Which of these is a legitimate way to use AI to support your studying?", options:["Having AI impersonate you in an online proctored exam","Submitting AI-written answers as your own on a graded test","Generating flashcards from your notes to review key terms","Paying AI to do your homework secretly"], answer:2, explain:"<strong>Generating flashcards from your notes to review key terms</strong> is a legitimate study aid that reinforces your own learning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Submitting AI-written answers as your own on a graded test</b>: this is academic dishonesty.</span><span class='qd'><b>Having AI impersonate you in an online proctored exam</b>: impersonation in an exam is clear cheating.</span><span class='qd'><b>Paying AI to do your homework secretly</b>: secretly outsourcing homework violates academic integrity and skips learning.</span>" },
{ id:"D5-056", domain:5, obj:"5.4", diff:"hard", q:"A student uses AI to explain a homework problem, understands the method, then solves a different assigned problem on their own. How is this BEST characterized?", options:["Cheating, because AI was involved at all","Plagiarism of the AI","A violation, because the student solved anything","Appropriate use of AI as a learning aid"], answer:3, explain:"<strong>Appropriate use of AI as a learning aid</strong> is correct: the student used AI to learn the method and then demonstrated understanding independently, which supports genuine learning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cheating, because AI was involved at all</b>: using AI to understand a concept and then working independently is a legitimate study method.</span><span class='qd'><b>A violation, because the student solved anything</b>: solving the assigned problem yourself is the intended outcome, not a violation.</span><span class='qd'><b>Plagiarism of the AI</b>: the student wrote their own solution, so nothing was copied.</span>" },
{ id:"D5-057", domain:5, obj:"5.4", diff:"medium", q:"Your school's policy on AI is unclear for a particular assignment. What is the MOST responsible step before using AI?", options:["Ask the instructor for clarification on what is permitted","Assume it is allowed and use it freely","Use AI but delete the chat history","Avoid all technology, including calculators"], answer:0, explain:"<strong>Ask the instructor for clarification on what is permitted</strong> is the responsible move when a policy is ambiguous, ensuring you stay within the rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is allowed and use it freely</b>: assuming permission risks an integrity violation if you guess wrong.</span><span class='qd'><b>Use AI but delete the chat history</b>: hiding your usage suggests you know it may not be allowed and is dishonest.</span><span class='qd'><b>Avoid all technology, including calculators</b>: this overcorrects and is unrelated to clarifying the AI policy.</span>" },
{ id:"D5-058", domain:5, obj:"5.4", diff:"medium", q:"How can AI help you prepare for an interview in a way that builds your own skills?", options:["By attending the interview in your place","By running mock interviews where it asks questions and gives feedback on your answers","By writing answers for you to memorize word-for-word","By guaranteeing you the job"], answer:1, explain:"<strong>By running mock interviews where it asks questions and gives feedback on your answers</strong> lets you practice and improve your own responses, which genuinely builds interview skills.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>By attending the interview in your place</b>: an AI cannot and should not stand in for you at an interview.</span><span class='qd'><b>By writing answers for you to memorize word-for-word</b>: memorized scripts sound rehearsed and fail when questions differ.</span><span class='qd'><b>By guaranteeing you the job</b>: no tool can guarantee a hiring outcome.</span>" },
{ id:"D5-059", domain:5, obj:"5.4", diff:"easy", q:"What is a good sign that you are using AI as a study partner effectively?", options:["You never had to think during the session","You memorized the AI's exact wording without understanding it","You can now explain the concept in your own words","You skipped reviewing the material entirely"], answer:2, explain:"<strong>You can now explain the concept in your own words</strong> demonstrates real understanding, which is the goal of studying with AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>You memorized the AI's exact wording without understanding it</b>: rote memorization without understanding is shallow and fragile.</span><span class='qd'><b>You never had to think during the session</b>: effective learning requires active thinking, not passivity.</span><span class='qd'><b>You skipped reviewing the material entirely</b>: skipping the material means you did not actually learn it.</span>" },
{ id:"D5-060", domain:5, obj:"5.4", diff:"hard", q:"A student asks AI to \"summarize this chapter so I don't have to read it,\" then relies solely on the summary for an exam and performs poorly. What lesson BEST explains this outcome?", options:["Summaries are always inaccurate","AI cannot summarize chapters","The student should have asked for a longer summary","AI summaries can omit nuance and details, so they support but do not replace real study"], answer:3, explain:"<strong>AI summaries can omit nuance and details, so they support but do not replace real study</strong> captures the lesson: summaries are aids, not substitutes for engaging with the material.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Summaries are always inaccurate</b>: summaries are often accurate but necessarily incomplete; the problem is over-reliance, not constant inaccuracy.</span><span class='qd'><b>The student should have asked for a longer summary</b>: length alone does not restore the depth of actually studying the chapter.</span><span class='qd'><b>AI cannot summarize chapters</b>: AI can summarize; the issue is treating the summary as a full replacement for study.</span>" },
{ id:"D5-061", domain:5, obj:"5.4", diff:"medium", q:"You want AI to help you memorize vocabulary for a language class. Which technique is MOST supported by using AI well?", options:["Asking AI to spaced-repeat quiz you and gradually increase difficulty","Asking AI to take your quiz for you","Reading the AI's output once and stopping","Asking AI to skip the words you find hard"], answer:0, explain:"<strong>Asking AI to spaced-repeat quiz you and gradually increase difficulty</strong> uses proven active-recall and spacing techniques that strengthen memory.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking AI to take your quiz for you</b>: having AI take the quiz teaches you nothing.</span><span class='qd'><b>Reading the AI's output once and stopping</b>: a single passive read is far less effective than repeated active recall.</span><span class='qd'><b>Asking AI to skip the words you find hard</b>: skipping hard words avoids exactly the material you most need to practice.</span>" },
{ id:"D5-062", domain:5, obj:"5.4", diff:"medium", q:"An instructor permits AI for studying but not for producing submitted answers. A student uses AI to generate a practice explanation and then writes their own submission. This is:", options:["A violation of the policy","Consistent with the policy","Only allowed if the student pays for AI","Cheating because AI was opened at all"], answer:1, explain:"<strong>Consistent with the policy</strong> is correct: studying with AI is permitted, and the student produced their submitted work themselves.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A violation of the policy</b>: the policy allows AI for studying, which is exactly what the student did.</span><span class='qd'><b>Only allowed if the student pays for AI</b>: payment status is irrelevant to policy compliance.</span><span class='qd'><b>Cheating because AI was opened at all</b>: permitted study use is not cheating.</span>" },
{ id:"D5-063", domain:5, obj:"5.4", diff:"hard", q:"A student notices an AI tutor confidently gave two contradictory explanations of the same rule across two sessions. What is the MOST appropriate takeaway?", options:["AI tutors are useless and should never be used","Always trust the more recent explanation","Cross-check AI explanations with a textbook or teacher when consistency matters","Contradiction proves the topic has no correct answer"], answer:2, explain:"<strong>Cross-check AI explanations with a textbook or teacher when consistency matters</strong> is the right takeaway: contradictions signal you should verify with an authoritative source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI tutors are useless and should never be used</b>: AI tutors are useful when their output is verified; one inconsistency does not make them useless.</span><span class='qd'><b>Always trust the more recent explanation</b>: recency does not indicate correctness.</span><span class='qd'><b>Contradiction proves the topic has no correct answer</b>: the contradiction reflects AI variability, not the absence of a correct answer.</span>" },
{ id:"D5-064", domain:5, obj:"5.4", diff:"easy", q:"Which study aid can AI reasonably help you create from your own notes?", options:["A copy of the actual exam answers","A forged transcript with fake grades","A way to bypass exam proctoring","A set of practice questions to test yourself"], answer:3, explain:"<strong>A set of practice questions to test yourself</strong> is a legitimate, helpful study aid AI can generate from your notes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A forged transcript with fake grades</b>: forging records is fraud, not a study aid.</span><span class='qd'><b>A way to bypass exam proctoring</b>: circumventing proctoring is cheating.</span><span class='qd'><b>A copy of the actual exam answers</b>: obtaining exam answers is an integrity violation.</span>" },
{ id:"D5-065", domain:5, obj:"5.5", diff:"easy", q:"You are deciding between two vendors and want AI to be a thought partner. What is the BEST way to use it?", options:["Ask it to list pros, cons, and questions to consider for each option","Ask it to make the final decision so you don't have to","Ask it which vendor is objectively best with no context","Ask it to pick randomly"], answer:0, explain:"<strong>Ask it to list pros, cons, and questions to consider for each option</strong> uses AI to structure your thinking and surface considerations, keeping the decision yours.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask it to make the final decision so you don't have to</b>: offloading the decision ignores context only you have and abdicates your responsibility.</span><span class='qd'><b>Ask it which vendor is objectively best with no context</b>: without your context the AI cannot know what \"best\" means for you.</span><span class='qd'><b>Ask it to pick randomly</b>: a random pick wastes the analytical value AI can provide.</span>" },
{ id:"D5-066", domain:5, obj:"5.5", diff:"medium", q:"You paste sales data and ask AI to help you interpret it. What is the MOST important caution?", options:["AI will always interpret data perfectly","Verify the AI's calculations and conclusions, since it can misread or invent trends","Data interpretation is impossible for AI","You should never look at the data yourself"], answer:1, explain:"<strong>Verify the AI's calculations and conclusions, since it can misread or invent trends</strong> is essential, because AI may draw incorrect inferences that look convincing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI will always interpret data perfectly</b>: AI can make analytical errors, so perfection cannot be assumed.</span><span class='qd'><b>Data interpretation is impossible for AI</b>: AI can help interpret data; it just needs verification.</span><span class='qd'><b>You should never look at the data yourself</b>: reviewing the data yourself is exactly how you catch AI mistakes.</span>" },
{ id:"D5-067", domain:5, obj:"5.5", diff:"medium", q:"You ask AI to help evaluate a business scenario, and it gives a confident recommendation. What should you do before acting on it?", options:["Act immediately because it sounded confident","Assume confidence equals correctness","Consider the assumptions behind the recommendation and whether they fit your real situation","Ask it to be even more confident"], answer:2, explain:"<strong>Consider the assumptions behind the recommendation and whether they fit your real situation</strong> is the right check: AI advice rests on assumptions that may not match your context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Act immediately because it sounded confident</b>: confidence is not a reliable indicator of correctness.</span><span class='qd'><b>Assume confidence equals correctness</b>: this is a common trap; confident tone can accompany flawed reasoning.</span><span class='qd'><b>Ask it to be even more confident</b>: more confidence adds nothing to the soundness of the advice.</span>" },
{ id:"D5-068", domain:5, obj:"5.5", diff:"hard", q:"A manager uses AI to weigh three strategies. The AI favors one but omits a major regulatory constraint the manager knows applies. What is the BEST response?", options:["Follow the AI's favored strategy anyway","Assume the regulation no longer applies","Discard AI for all decisions permanently","Add the regulatory constraint to the analysis and reassess, since AI lacked that context"], answer:3, explain:"<strong>Add the regulatory constraint to the analysis and reassess, since AI lacked that context</strong> corrects the analysis by supplying knowledge the AI did not have, leading to a sounder decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Follow the AI's favored strategy anyway</b>: proceeding while ignoring a known regulatory constraint invites serious problems.</span><span class='qd'><b>Discard AI for all decisions permanently</b>: the fix is to add missing context, not abandon a useful tool over one gap.</span><span class='qd'><b>Assume the regulation no longer applies</b>: assuming away a known constraint without checking is reckless.</span>" },
{ id:"D5-069", domain:5, obj:"5.5", diff:"medium", q:"Why is it useful to ask AI to argue BOTH sides of a decision you are facing?", options:["It surfaces considerations and counterarguments you might have overlooked","It guarantees the AI is unbiased","It removes the need to decide","It proves both sides are equally valid"], answer:0, explain:"<strong>It surfaces considerations and counterarguments you might have overlooked</strong> is the benefit: hearing both sides broadens your view before you decide.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the AI is unbiased</b>: presenting both sides does not certify the AI has no bias.</span><span class='qd'><b>It removes the need to decide</b>: you still must weigh the arguments and choose.</span><span class='qd'><b>It proves both sides are equally valid</b>: arguing both sides does not make them equally strong; it just informs your judgment.</span>" },
{ id:"D5-070", domain:5, obj:"5.5", diff:"easy", q:"When using AI to think through a personal financial decision, what is a sensible limit to keep in mind?", options:["AI knows your full financial situation automatically","AI can offer general considerations, but it is not a substitute for a qualified professional when stakes are high","AI decisions are legally binding","You must follow whatever the AI suggests"], answer:1, explain:"<strong>AI can offer general considerations, but it is not a substitute for a qualified professional when stakes are high</strong> sets a realistic boundary for high-stakes personal decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI knows your full financial situation automatically</b>: it only knows what you tell it.</span><span class='qd'><b>AI decisions are legally binding</b>: AI output carries no legal authority.</span><span class='qd'><b>You must follow whatever the AI suggests</b>: you are free to weigh AI input and decide for yourself.</span>" },
{ id:"D5-071", domain:5, obj:"5.5", diff:"hard", q:"You give AI a spreadsheet summary and it reports a trend, but you notice the trend contradicts what you observed in the raw numbers. What is the MOST appropriate step?", options:["Trust the AI over your own reading","Delete the spreadsheet","Re-examine both the raw data and the AI's reasoning to find where the discrepancy comes from","Ask the AI to report a different trend"], answer:2, explain:"<strong>Re-examine both the raw data and the AI's reasoning to find where the discrepancy comes from</strong> is the sound approach: a conflict signals a possible error on either side that you should investigate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the AI over your own reading</b>: blindly trusting the AI ignores a legitimate red flag you spotted.</span><span class='qd'><b>Delete the spreadsheet</b>: deleting the data destroys the very information needed to resolve the discrepancy.</span><span class='qd'><b>Ask the AI to report a different trend</b>: asking for a different answer without understanding the conflict does not establish the truth.</span>" },
{ id:"D5-072", domain:5, obj:"5.5", diff:"medium", q:"Which prompt BEST uses AI as a thought partner for evaluating a proposed office relocation?", options:["\"Should we move? Yes or no.\"","\"Tell me moving is always a bad idea.\"","\"Move the office for us.\"","\"Help me evaluate this office move: list benefits, risks, costs, and key questions we should answer first.\""], answer:3, explain:"<strong>\"Help me evaluate this office move: list benefits, risks, costs, and key questions we should answer first.\"</strong> structures a thorough evaluation, which is how AI adds value to a complex decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Should we move? Yes or no.\"</b>: a bare yes/no ignores the analysis you need to decide well.</span><span class='qd'><b>\"Move the office for us.\"</b>: an AI cannot execute a relocation; it can only help you think it through.</span><span class='qd'><b>\"Tell me moving is always a bad idea.\"</b>: asking for a predetermined answer biases the analysis and is not genuine evaluation.</span>" },
{ id:"D5-073", domain:5, obj:"5.5", diff:"medium", q:"An AI helps you compare options and recommends the choice that happens to be easiest to describe, not necessarily the best. What does this remind you to do?", options:["Apply your own judgment and real-world knowledge, since AI may favor what is simple to articulate","Always pick the easiest option","Trust that easy-to-explain means best","Stop comparing options"], answer:0, explain:"<strong>Apply your own judgment and real-world knowledge, since AI may favor what is simple to articulate</strong> is the lesson: AI output can reflect articulation bias rather than true merit, so human judgment matters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Always pick the easiest option</b>: ease of description is not a measure of quality.</span><span class='qd'><b>Trust that easy-to-explain means best</b>: simple to explain and actually best are not the same thing.</span><span class='qd'><b>Stop comparing options</b>: comparing is still valuable; you just add your own judgment to the AI's output.</span>" },
{ id:"D5-074", domain:5, obj:"5.5", diff:"hard", q:"You ask AI to model outcomes for a decision under uncertainty. It gives precise-looking numbers. Why should you treat these numbers cautiously?", options:["Precise numbers from AI are always exact","The precision can create false confidence; the underlying assumptions may be rough or invented","AI cannot produce numbers","Numbers are irrelevant to decisions"], answer:1, explain:"<strong>The precision can create false confidence; the underlying assumptions may be rough or invented</strong> warns against being misled by exact-looking figures that rest on shaky assumptions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Precise numbers from AI are always exact</b>: apparent precision does not guarantee accuracy.</span><span class='qd'><b>AI cannot produce numbers</b>: AI readily produces numbers; the caution is about trusting them.</span><span class='qd'><b>Numbers are irrelevant to decisions</b>: numbers can inform decisions; they simply must be scrutinized.</span>" },
{ id:"D5-075", domain:5, obj:"5.5", diff:"easy", q:"What is a realistic expectation when using AI to help evaluate options?", options:["It replaces the need for stakeholders and expertise","It always knows the correct choice","It can organize considerations and trade-offs to inform, not replace, your decision","It removes all uncertainty"], answer:2, explain:"<strong>It can organize considerations and trade-offs to inform, not replace, your decision</strong> is the realistic role of AI: a structuring aid, not a decision-maker.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It replaces the need for stakeholders and expertise</b>: real decisions still need human stakeholders and expertise.</span><span class='qd'><b>It always knows the correct choice</b>: AI does not have a guaranteed correct answer for your specific situation.</span><span class='qd'><b>It removes all uncertainty</b>: uncertainty remains; AI can only help you reason about it.</span>" },
{ id:"D5-076", domain:5, obj:"5.5", diff:"medium", q:"You want AI to stress-test your plan. Which request is MOST useful?", options:["\"Tell me my plan is great.\"","\"Agree with everything I say.\"","\"Rewrite my plan to be longer.\"","\"Play devil's advocate: what could go wrong with this plan and what am I overlooking?\""], answer:3, explain:"<strong>\"Play devil's advocate: what could go wrong with this plan and what am I overlooking?\"</strong> invites critical challenge, which is exactly how a stress test strengthens a plan.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Tell me my plan is great.\"</b>: seeking praise avoids the scrutiny a stress test requires.</span><span class='qd'><b>\"Rewrite my plan to be longer.\"</b>: length does not test the plan's weaknesses.</span><span class='qd'><b>\"Agree with everything I say.\"</b>: forced agreement suppresses the useful pushback you are after.</span>" },
{ id:"D5-077", domain:5, obj:"5.5", diff:"hard", q:"A team lead uses AI to evaluate candidates from resumes. What is the MOST important fairness caution?", options:["AI can reflect biases and miss context, so its assessments should not be the sole basis for decisions about people","AI is always perfectly objective about people","Resumes contain no useful information","AI should make the hiring decision alone"], answer:0, explain:"<strong>AI can reflect biases and miss context, so its assessments should not be the sole basis for decisions about people</strong> is critical for fairness in high-stakes decisions about individuals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI is always perfectly objective about people</b>: AI can carry and amplify biases, so it is not perfectly objective.</span><span class='qd'><b>Resumes contain no useful information</b>: resumes do contain useful information; the caution is about how AI evaluates them.</span><span class='qd'><b>AI should make the hiring decision alone</b>: sole reliance on AI for hiring risks unfair and context-blind outcomes.</span>" },
{ id:"D5-078", domain:5, obj:"5.6", diff:"easy", q:"You used AI to help draft a report at work. In many workplaces, what is the honest thing to do about that?", options:["Hide it completely so no one knows","Be transparent about AI's role according to your organization's expectations","Claim you did not use any tools","Credit a coworker for the AI's contribution"], answer:1, explain:"<strong>Be transparent about AI's role according to your organization's expectations</strong> is the honest, professional approach to disclosing AI assistance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hide it completely so no one knows</b>: concealment can violate policy and erode trust if disclosure is expected.</span><span class='qd'><b>Claim you did not use any tools</b>: falsely denying tool use is dishonest.</span><span class='qd'><b>Credit a coworker for the AI's contribution</b>: misattributing the work to a colleague is false and unfair.</span>" },
{ id:"D5-079", domain:5, obj:"5.6", diff:"easy", q:"Which statement is the MOST accurate way to communicate how AI contributed to a piece of writing?", options:["\"This was written entirely by a human with no assistance.\"","\"AI wrote this and it is guaranteed accurate.\"","\"AI assisted with drafting and I reviewed and edited the final version.\"","\"No tools were used at any point.\""], answer:2, explain:"<strong>\"AI assisted with drafting and I reviewed and edited the final version.\"</strong> accurately describes a common human-plus-AI workflow and your accountability for the result.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"This was written entirely by a human with no assistance.\"</b>: this is false if AI helped.</span><span class='qd'><b>\"AI wrote this and it is guaranteed accurate.\"</b>: claiming a guarantee of accuracy is misleading, since AI can err.</span><span class='qd'><b>\"No tools were used at any point.\"</b>: denying tool use when AI was involved is dishonest.</span>" },
{ id:"D5-080", domain:5, obj:"5.6", diff:"medium", q:"Your organization requires disclosing AI use in client deliverables. You used AI to summarize research but wrote the analysis yourself. What is the BEST disclosure?", options:["Say nothing, since you wrote the analysis","Disclose only if the client asks","Claim AI wrote the entire deliverable","Note that AI was used to summarize source research and that the analysis is your own"], answer:3, explain:"<strong>Note that AI was used to summarize source research and that the analysis is your own</strong> is accurate and specific, meeting the disclosure requirement honestly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Say nothing, since you wrote the analysis</b>: the policy requires disclosing the AI use that did occur, even if partial.</span><span class='qd'><b>Claim AI wrote the entire deliverable</b>: overstating AI's role is as inaccurate as understating it.</span><span class='qd'><b>Disclose only if the client asks</b>: a disclosure requirement is not contingent on the client asking.</span>" },
{ id:"D5-081", domain:5, obj:"5.6", diff:"medium", q:"Why does clearly communicating how AI contributed build trust with your audience?", options:["It sets accurate expectations and shows integrity about the process","It makes the work look more expensive","It hides mistakes","It transfers all responsibility to the AI"], answer:0, explain:"<strong>It sets accurate expectations and shows integrity about the process</strong> is why transparency builds trust: honesty about the process reassures your audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the work look more expensive</b>: cost perception is unrelated to disclosing AI use.</span><span class='qd'><b>It hides mistakes</b>: transparency reveals process honestly rather than concealing errors.</span><span class='qd'><b>It transfers all responsibility to the AI</b>: disclosing AI use does not offload your responsibility for the work.</span>" },
{ id:"D5-082", domain:5, obj:"5.6", diff:"hard", q:"A journalist uses AI to help generate interview questions but conducts and writes the story herself. A reader asks whether AI was involved. What is the MOST responsible answer?", options:["\"No AI was involved in any way.\"","\"AI helped brainstorm some interview questions; the reporting and writing are my own.\"","\"The AI wrote the whole article.\"","Refuse to answer the question"], answer:1, explain:"<strong>\"AI helped brainstorm some interview questions; the reporting and writing are my own.\"</strong> is precise and honest about the limited role AI played.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"No AI was involved in any way.\"</b>: this is false, since AI helped with the questions.</span><span class='qd'><b>\"The AI wrote the whole article.\"</b>: this overstates AI's role and misrepresents the journalist's work.</span><span class='qd'><b>Refuse to answer the question</b>: refusing to answer a direct, reasonable question undermines trust.</span>" },
{ id:"D5-083", domain:5, obj:"5.6", diff:"medium", q:"You are submitting a photo contest entry. The image was AI-generated. The rules require original photography. What should you do?", options:["Submit it and hope no one notices","Relabel it as a scanned negative","Do not submit it as photography, since it does not meet the rules; disclose it is AI-generated","Argue that AI counts as a camera"], answer:2, explain:"<strong>Do not submit it as photography, since it does not meet the rules; disclose it is AI-generated</strong> respects the contest rules and communicates the true origin of the image.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Submit it and hope no one notices</b>: entering an ineligible image and hoping to avoid detection is dishonest.</span><span class='qd'><b>Relabel it as a scanned negative</b>: fabricating an origin is a lie.</span><span class='qd'><b>Argue that AI counts as a camera</b>: this misrepresents what the rules mean by original photography.</span>" },
{ id:"D5-084", domain:5, obj:"5.6", diff:"easy", q:"What does responsible attribution of AI assistance mainly protect?", options:["The AI company's profits","The length of your document","The speed of your computer","Honesty and trust between you and the people relying on your work"], answer:3, explain:"<strong>Honesty and trust between you and the people relying on your work</strong> is what proper attribution protects, keeping your communication credible.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI company's profits</b>: attribution is about honesty with your audience, not vendor revenue.</span><span class='qd'><b>The speed of your computer</b>: disclosure has no effect on performance.</span><span class='qd'><b>The length of your document</b>: attribution does not concern document length.</span>" },
{ id:"D5-085", domain:5, obj:"5.6", diff:"hard", q:"A consultant delivers an AI-assisted market analysis without disclosure, and later a client discovers AI was heavily involved and some figures were wrong. What is the core lesson?", options:["Disclose AI's role and verify outputs, because hidden use plus unverified errors damages trust","Never use AI for client work","Clients should have assumed AI was used","Errors are always the client's fault"], answer:0, explain:"<strong>Disclose AI's role and verify outputs, because hidden use plus unverified errors damages trust</strong> combines the two failures here: concealment and lack of verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never use AI for client work</b>: AI can be used responsibly with disclosure and verification; a total ban is an overreaction.</span><span class='qd'><b>Clients should have assumed AI was used</b>: the burden of disclosure is on the consultant, not on the client to guess.</span><span class='qd'><b>Errors are always the client's fault</b>: the consultant who delivered the work owns its accuracy.</span>" },
{ id:"D5-086", domain:5, obj:"5.6", diff:"medium", q:"When a template or workplace form asks whether AI tools were used, the BEST practice is to:", options:["Leave it blank to avoid the topic","Answer accurately based on how you actually used AI","Always answer no to appear more skilled","Always answer yes even if you did not use AI"], answer:1, explain:"<strong>Answer accurately based on how you actually used AI</strong> is the straightforward honest response to a disclosure prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Leave it blank to avoid the topic</b>: dodging the question fails to provide the required disclosure.</span><span class='qd'><b>Always answer no to appear more skilled</b>: a blanket no is dishonest if you did use AI.</span><span class='qd'><b>Always answer yes even if you did not use AI</b>: a false yes is also inaccurate; the answer should reflect reality.</span>" },
{ id:"D5-087", domain:5, obj:"5.1", diff:"medium", q:"You want AI to help you break a big, intimidating project into a starting point. Which request is MOST helpful for overcoming that initial overwhelm?", options:["\"Do the whole project for me.\"","\"Tell me the project is too hard.\"","\"Break this project into a few manageable first steps I can start today.\"","\"Give me every possible detail at once.\""], answer:2, explain:"<strong>\"Break this project into a few manageable first steps I can start today.\"</strong> converts an overwhelming task into a concrete starting point, which is a proven way to beat inertia.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Do the whole project for me.\"</b>: outsourcing the whole project is unrealistic and skips your involvement and learning.</span><span class='qd'><b>\"Tell me the project is too hard.\"</b>: reinforcing that it is hard increases avoidance rather than helping you start.</span><span class='qd'><b>\"Give me every possible detail at once.\"</b>: a flood of detail can deepen the overwhelm instead of easing it.</span>" },
{ id:"D5-088", domain:5, obj:"5.2", diff:"hard", q:"You need one core message adapted into an email, a social post, and a slide headline. What is the MOST efficient effective prompt?", options:["\"Write something about this.\"","\"Only give me the email and ignore the rest.\"","\"Write a 3,000-word article.\"","\"Take this key message and adapt it into three formats: a short email, a social post, and a one-line slide headline.\""], answer:3, explain:"<strong>\"Take this key message and adapt it into three formats: a short email, a social post, and a one-line slide headline.\"</strong> asks for all three tailored formats in one clear instruction, matching each channel's needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Write something about this.\"</b>: this is too vague to produce the three specific formats you need.</span><span class='qd'><b>\"Write a 3,000-word article.\"</b>: a long article does not give you the concise multi-format outputs requested.</span><span class='qd'><b>\"Only give me the email and ignore the rest.\"</b>: this drops two of the three formats you actually need.</span>" },
{ id:"D5-089", domain:5, obj:"5.3", diff:"medium", q:"You use AI to critique a photo you took, and it suggests edits. What is the MOST sensible way to treat its suggestions?", options:["Weigh each suggestion against your own artistic intent and keep what improves the photo","Apply every suggestion without looking","Reject all suggestions because AI has no taste","Ask the AI to guarantee the photo will win awards"], answer:0, explain:"<strong>Weigh each suggestion against your own artistic intent and keep what improves the photo</strong> treats AI critique as input to your judgment rather than orders to follow.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Apply every suggestion without looking</b>: blindly applying edits can work against your intent and the image's strengths.</span><span class='qd'><b>Reject all suggestions because AI has no taste</b>: dismissing all feedback outright discards potentially useful observations.</span><span class='qd'><b>Ask the AI to guarantee the photo will win awards</b>: no tool can guarantee such an outcome.</span>" },
{ id:"D5-090", domain:5, obj:"5.4", diff:"medium", q:"A study group wants AI to generate a practice exam. What step ensures the practice exam actually helps them learn?", options:["Read the answers first, then take the exam","Take the practice exam, then review explanations for every wrong answer","Skip the questions they find difficult","Memorize the practice questions expecting the real exam to be identical"], answer:1, explain:"<strong>Take the practice exam, then review explanations for every wrong answer</strong> is effective study: testing plus targeted review of mistakes builds understanding.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Read the answers first, then take the exam</b>: seeing answers first removes the retrieval practice that makes testing useful.</span><span class='qd'><b>Skip the questions they find difficult</b>: skipping hard questions avoids the material most in need of practice.</span><span class='qd'><b>Memorize the practice questions expecting the real exam to be identical</b>: real exams differ, so memorizing specific items is a poor strategy.</span>" },
{ id:"D5-091", domain:5, obj:"5.5", diff:"medium", q:"You ask AI to help you choose a project management approach for your team. What information will MOST improve its usefulness as a thought partner?", options:["The AI's favorite methodology","The current date only","Your team size, deadlines, experience level, and the kind of work you do","The price of project management software"], answer:2, explain:"<strong>Your team size, deadlines, experience level, and the kind of work you do</strong> gives the AI the real constraints it needs to tailor its analysis to your situation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI's favorite methodology</b>: an AI has no genuine preference, and this adds no useful context.</span><span class='qd'><b>The current date only</b>: the date alone does not describe your team or its needs.</span><span class='qd'><b>The price of project management software</b>: cost of tools is a minor detail compared to your team's actual characteristics.</span>" },
{ id:"D5-092", domain:5, obj:"5.6", diff:"medium", q:"A colleague asks if the polished proposal you shared was AI-assisted. It was. What response BEST balances honesty and professionalism?", options:["\"Absolutely not, all me.\"","\"The AI is fully responsible for it.\"","\"Why does it matter to you?\"","\"Yes, I used AI to help draft it and then revised it thoroughly myself.\""], answer:3, explain:"<strong>\"Yes, I used AI to help draft it and then revised it thoroughly myself.\"</strong> is honest about the assistance while affirming your ownership and effort.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Absolutely not, all me.\"</b>: this is a false denial.</span><span class='qd'><b>\"Why does it matter to you?\"</b>: a defensive deflection avoids a fair question and hurts trust.</span><span class='qd'><b>\"The AI is fully responsible for it.\"</b>: you, not the AI, are responsible for work you share.</span>" },
{ id:"D5-093", domain:5, obj:"5.1", diff:"hard", q:"You want AI to help you generate ideas, but you also want to keep your own creative voice strong. Which workflow BEST balances both?", options:["Use AI to spark options, then select, combine, and rewrite them in your own voice","Let AI generate everything and use it unchanged","Never look at AI output","Copy AI ideas exactly and claim them as fully original"], answer:0, explain:"<strong>Use AI to spark options, then select, combine, and rewrite them in your own voice</strong> keeps AI as an idea catalyst while your voice shapes the final result.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let AI generate everything and use it unchanged</b>: unchanged AI output tends to sound generic and erases your voice.</span><span class='qd'><b>Never look at AI output</b>: refusing to use it forfeits the brainstorming benefit entirely.</span><span class='qd'><b>Copy AI ideas exactly and claim them as fully original</b>: claiming unedited AI output as fully your own is neither accurate nor a way to preserve your voice.</span>" },
{ id:"D5-094", domain:5, obj:"5.2", diff:"easy", q:"You ask AI to draft a message and specify \"keep it under 100 words.\" Why is giving a length constraint helpful?", options:["It makes the AI think longer","It produces output sized to fit your channel and your reader's time","Short messages are always better than long ones","It prevents the AI from making mistakes"], answer:1, explain:"<strong>It produces output sized to fit your channel and your reader's time</strong> is the practical benefit of a length constraint: the message fits where and how it will be read.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the AI think longer</b>: a length limit does not change how the AI processes the request.</span><span class='qd'><b>Short messages are always better than long ones</b>: the right length depends on the situation, not a blanket rule.</span><span class='qd'><b>It prevents the AI from making mistakes</b>: a word limit controls length, not factual accuracy.</span>" },
{ id:"D5-095", domain:5, obj:"5.3", diff:"easy", q:"You created a graphic with an AI tool for a public post. When is disclosing that it is AI-generated MOST clearly appropriate?", options:["Never, since disclosure is embarrassing","Only if the image looks bad","When your audience would reasonably assume it is a real photo or human-made art","Only after someone accuses you"], answer:2, explain:"<strong>When your audience would reasonably assume it is a real photo or human-made art</strong> pinpoints when disclosure matters: whenever omission would mislead about the image's origin.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never, since disclosure is embarrassing</b>: disclosure is about honesty, not embarrassment, and hiding origin can mislead.</span><span class='qd'><b>Only if the image looks bad</b>: quality does not determine whether disclosure is warranted.</span><span class='qd'><b>Only after someone accuses you</b>: waiting to be accused is reactive; proactive honesty is the responsible norm.</span>" },
{ id:"D5-096", domain:5, obj:"5.4", diff:"medium", q:"You ask AI to act as a Socratic tutor. What behavior would indicate it is doing this WELL?", options:["It gives you the final answer immediately","It tells you the answer is too hard to explain","It refuses to interact","It asks you guiding questions that lead you to reason toward the answer yourself"], answer:3, explain:"<strong>It asks you guiding questions that lead you to reason toward the answer yourself</strong> is the essence of Socratic tutoring, which builds your understanding through guided thinking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It gives you the final answer immediately</b>: handing over the answer is the opposite of the Socratic method.</span><span class='qd'><b>It refuses to interact</b>: a tutor that will not engage cannot guide your reasoning.</span><span class='qd'><b>It tells you the answer is too hard to explain</b>: dismissing the question provides no learning value.</span>" },
{ id:"D5-097", domain:5, obj:"5.5", diff:"hard", q:"You use AI to compare two job offers. It weighs salary heavily and barely mentions factors like growth, culture, and commute that matter deeply to you. What is the BEST response?", options:["Add the factors that matter to you and ask it to weigh them, since it did not know your priorities","Accept its salary-focused recommendation","Assume salary is the only rational factor","Ask it to ignore salary entirely from now on"], answer:0, explain:"<strong>Add the factors that matter to you and ask it to weigh them, since it did not know your priorities</strong> corrects the analysis by supplying your personal priorities, which the AI could not have known.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept its salary-focused recommendation</b>: accepting a recommendation that ignores your key priorities can lead to a poor decision.</span><span class='qd'><b>Assume salary is the only rational factor</b>: many rational factors beyond salary matter in a job choice.</span><span class='qd'><b>Ask it to ignore salary entirely from now on</b>: overcorrecting by dropping salary is as unbalanced as overweighting it.</span>" },
{ id:"D5-098", domain:5, obj:"5.6", diff:"hard", q:"An academic conference asks authors to state any AI tools used in preparing a submission. You used AI only to check grammar. What is the MOST accurate disclosure?", options:["State that no tools were used","State that AI was used for grammar and language checking only","State that AI wrote the research","Decline to disclose because grammar checking is minor"], answer:1, explain:"<strong>State that AI was used for grammar and language checking only</strong> is precise about the narrow role AI played, meeting the disclosure request honestly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>State that no tools were used</b>: this is inaccurate since you used AI for grammar.</span><span class='qd'><b>State that AI wrote the research</b>: this overstates AI's role, which was limited to grammar.</span><span class='qd'><b>Decline to disclose because grammar checking is minor</b>: the request asks for any AI use, so even minor use should be stated.</span>" },
{ id:"D5-099", domain:5, obj:"5.2", diff:"medium", q:"You ask AI to translate the same announcement for both a technical team and a general audience. What should you provide to get the best two versions?", options:["Only the text, with no audience information","A request for the longest possible translations","The text plus a clear description of each audience and the tone each expects","Instructions to use identical wording for both"], answer:2, explain:"<strong>The text plus a clear description of each audience and the tone each expects</strong> lets the AI adapt vocabulary and framing appropriately for each group.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the text, with no audience information</b>: without audience context the AI cannot tailor the two versions well.</span><span class='qd'><b>A request for the longest possible translations</b>: length is not the goal; audience fit is.</span><span class='qd'><b>Instructions to use identical wording for both</b>: identical wording defeats the purpose of adapting to two different audiences.</span>" },
{ id:"D5-100", domain:5, obj:"5.5", diff:"hard", q:"After using AI as a thought partner on a major decision, what is the SINGLE most important principle to remember about the final choice?", options:["The AI is accountable for whatever you decide","The decision no longer requires human review","Whatever the AI recommended must be followed","You remain responsible for the decision and should own it based on your judgment"], answer:3, explain:"<strong>You remain responsible for the decision and should own it based on your judgment</strong> is the core principle: AI informs, but the human decision-maker is accountable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI is accountable for whatever you decide</b>: an AI tool bears no accountability for your choices.</span><span class='qd'><b>Whatever the AI recommended must be followed</b>: you are free to weigh AI input and decide differently.</span><span class='qd'><b>The decision no longer requires human review</b>: important decisions still require your judgment and review.</span>" }
);
